Example usage (abridged):

cfg := streamx.ReconnectConfig{
  MaxAttempts: 6,
  MaxElapsed:  2 * time.Minute,
  BaseDelay:   250 * time.Millisecond,
  MaxDelay:    5 * time.Second,
  RespectRetryAfter: true,
  RetryOnStatuses: []int{408, 429, 500, 502, 503, 504},
  CursorStore: streamx.NewInMemoryCursorStore(),
  Logger:      log.Default(),
}

err := streamx.StreamWithReconnect(ctx, cfg, func(ctx context.Context) (streamx.Stream, error) {
  // create a fresh stream each attempt
  return client.ChatCompletionsStream(ctx, req)
}, func(ev streamx.Event) (bool, error) {
  // idempotent processing recommended
  fmt.Print(ev.Delta)
  return true, nil
})
